// =============================================================================
// GPU Detection Edge Cases
// =============================================================================

describe('GPU Detection Edge Cases', () => {
    it('parses nvidia-smi output with 0 GPUs (empty output)', () => {
        const gpus = parseNvidiaSmiOutput('');
        expect(gpus).toEqual([]);
        expect(gpus.length).toBe(0);
    });

    it('parses nvidia-smi output with 8 GPUs', () => {
        const lines = [];
        for (let i = 0; i < 8; i++) {
            lines.push(`${i}, 00000000:0${i + 1}:00.0, NVIDIA A100-SXM4-80GB, ${20000 + i * 1000}, 81920, ${55 + i * 2}, ${70 + i}, 250.00, 0, 1410, 1215`);
        }
        const output = lines.join('\n');
        const gpus = parseNvidiaSmiOutput(output);

        expect(gpus.length).toBe(8);
        // Verify first and last GPU
        expect(gpus[0].busId).toBe('00000000:01:00.0');
        expect(gpus[0].name).toBe('NVIDIA A100-SXM4-80GB');
        expect(gpus[0].vramTotalMb).toBe(81920);
        expect(gpus[7].busId).toBe('00000000:08:00.0');
        expect(gpus[7].temperatureC).toBe(69);
        expect(gpus[7].utilizationPct).toBe(77);
    });

    it('handles malformed nvidia-smi output gracefully', () => {
        // Completely garbage input — single line with no commas
        const gpus1 = parseNvidiaSmiOutput('ERROR: NVIDIA driver not loaded');
        expect(gpus1.length).toBe(1);
        expect(gpus1[0].busId).toBe('unknown');
        expect(gpus1[0].name).toBe('Unknown GPU');
        expect(gpus1[0].vramTotalMb).toBe(0);
        expect(gpus1[0].utilizationPct).toBe(0);

        // Partial fields — fewer fields than expected
        const gpus2 = parseNvidiaSmiOutput('0, 00000000:01:00.0, RTX 3090');
        expect(gpus2.length).toBe(1);
        expect(gpus2[0].busId).toBe('00000000:01:00.0');
        expect(gpus2[0].name).toBe('RTX 3090');
        expect(gpus2[0].vramTotalMb).toBe(0); // missing field → 0
        expect(gpus2[0].temperatureC).toBe(0);

        // Mix of valid and garbage lines
        const gpus3 = parseNvidiaSmiOutput([
            '0, 00000000:01:00.0, RTX 4090, 12000, 24576, 60, 90, 350.00, 55, 2100, 10500',
            'garbage-line-no-commas',
        ].join('\n'));
        expect(gpus3.length).toBe(2);
        expect(gpus3[0].name).toBe('RTX 4090');
        expect(gpus3[1].busId).toBe('unknown');
    });

    it('GPU name extraction handles unusual characters', () => {
        // GPU names with special characters, extra spaces, unicode
        const output = '0, 00000000:01:00.0, NVIDIA GeForce RTX 4070 Ti SUPER (TM), 8000, 16384, 55, 40, 180.00, 45, 2100, 10500';
        const gpus = parseNvidiaSmiOutput(output);
        expect(gpus.length).toBe(1);
        expect(gpus[0].name).toBe('NVIDIA GeForce RTX 4070 Ti SUPER (TM)');

        // Name with slashes and numbers
        const output2 = '0, 00000000:01:00.0, AMD/ATI Radeon RX 7900 XTX [Navi 31], 10000, 24576, 70, 85, 300.00, 60, 2500, 1200';
        const gpus2 = parseNvidiaSmiOutput(output2);
        expect(gpus2[0].name).toBe('AMD/ATI Radeon RX 7900 XTX [Navi 31]');
    });
});

