// Re-implementation of getMockGpuStats logic for testing
const MOCK_GPU_PRESETS = [
    { name: 'NVIDIA GeForce RTX 3090', vramTotalMb: 24576, powerMax: 350, clockBase: 1700, memClock: 9750 },
    { name: 'NVIDIA GeForce RTX 4070 Ti Super', vramTotalMb: 16384, powerMax: 285, clockBase: 2310, memClock: 10500 },
    { name: 'NVIDIA GeForce RTX 4090', vramTotalMb: 24576, powerMax: 450, clockBase: 2520, memClock: 10500 },
    { name: 'NVIDIA GeForce RTX 3060', vramTotalMb: 12288, powerMax: 170, clockBase: 1777, memClock: 7500 },
];

function getMockGpuStatsLocal(gpuCount: number): GpuStats[] {
    const gpus: GpuStats[] = [];
    for (let i = 0; i < gpuCount; i++) {
        const preset = MOCK_GPU_PRESETS[i % MOCK_GPU_PRESETS.length];
        const utilization = 30 + Math.random() * 60;
        gpus.push({
            busId: '0000:0' + (i + 1) + ':00.0',
            name: preset.name,
            vramTotalMb: preset.vramTotalMb,
            vramUsedMb: Math.round(preset.vramTotalMb * (0.3 + Math.random() * 0.5)),
            temperatureC: Math.round(45 + Math.random() * 30),
            utilizationPct: Math.round(utilization),
            powerDrawW: Math.round(preset.powerMax * (utilization / 100) * (0.8 + Math.random() * 0.2)),
            fanSpeedPct: Math.round(30 + Math.random() * 50),
            clockSmMhz: Math.round(preset.clockBase * (0.95 + Math.random() * 0.1)),
            clockMemMhz: preset.memClock,
        });
    }
    return gpus;
}

describe('Mock GPU Stats', () => {
    it('getMockGpuStats() with 0 GPUs returns empty array', () => {
        const gpus = getMockGpuStatsLocal(0);
        expect(gpus).toEqual([]);
        expect(gpus.length).toBe(0);
    });

    it('getMockGpuStats() with 1 GPU returns single GPU', () => {
        const gpus = getMockGpuStatsLocal(1);
        expect(gpus.length).toBe(1);
        expect(gpus[0].name).toBe('NVIDIA GeForce RTX 3090');
        expect(gpus[0].busId).toBe('0000:01:00.0');
        expect(gpus[0].vramTotalMb).toBe(24576);
    });

    it('Mock GPU stats have valid temperature range (0-120)', () => {
        // Run multiple times to exercise random range
        for (let run = 0; run < 10; run++) {
            const gpus = getMockGpuStatsLocal(4);
            for (const gpu of gpus) {
                expect(gpu.temperatureC).toBeGreaterThanOrEqual(0);
                expect(gpu.temperatureC).toBeLessThanOrEqual(120);
            }
        }
    });

    it('Mock GPU stats have valid utilization range (0-100)', () => {
        for (let run = 0; run < 10; run++) {
            const gpus = getMockGpuStatsLocal(4);
            for (const gpu of gpus) {
                expect(gpu.utilizationPct).toBeGreaterThanOrEqual(0);
                expect(gpu.utilizationPct).toBeLessThanOrEqual(100);
            }
        }
    });
});

