const MOCK_MODELS = ['llama3.1:8b', 'hermes3:8b', 'codellama:7b', 'dolphin-mistral:7b', 'phi3:mini'];

// Re-implementation of getInferenceStats mock-mode logic for testing
function getInferenceStatsLocal(mockMode: boolean, mockGpuCount: number) {
    if (mockMode) {
        // CPU-only nodes (0 GPUs) run BitNet
        if (mockGpuCount === 0) {
            return {
                loaded_models: ['bitnet-b1.58'],
                in_flight_requests: Math.floor(Math.random() * 3),
                tokens_generated: 0,
                avg_latency_ms: Math.round(15 + Math.random() * 40),
            };
        }
        const count = 1 + Math.floor(Math.random() * 3);
        return {
            loaded_models: MOCK_MODELS.slice(0, count),
            in_flight_requests: Math.floor(Math.random() * 5),
            tokens_generated: 0,
            avg_latency_ms: Math.round(20 + Math.random() * 60),
        };
    }
    return { loaded_models: [], in_flight_requests: 0, tokens_generated: 0, avg_latency_ms: 0 };
}

describe('Inference Stats', () => {
    it('getInferenceStats(true) returns mock data with models', () => {
        const stats = getInferenceStatsLocal(true, 2);
        expect(stats.loaded_models).toBeDefined();
        expect(stats.loaded_models.length).toBeGreaterThan(0);
        // All returned models should be from the MOCK_MODELS list
        for (const model of stats.loaded_models) {
            expect(MOCK_MODELS).toContain(model);
        }
        expect(stats.in_flight_requests).toBeGreaterThanOrEqual(0);
        expect(stats.tokens_generated).toBe(0);
    });

    it('Mock inference stats have valid latency (positive number)', () => {
        for (let run = 0; run < 20; run++) {
            const stats = getInferenceStatsLocal(true, 2);
            expect(stats.avg_latency_ms).toBeGreaterThan(0);
            expect(stats.avg_latency_ms).toBeLessThanOrEqual(80); // max: round(20 + 60) = 80
            expect(Number.isInteger(stats.avg_latency_ms)).toBe(true);
        }
    });

    it('Mock inference stats for 0-GPU nodes return bitnet model', () => {
        for (let run = 0; run < 10; run++) {
            const stats = getInferenceStatsLocal(true, 0);
            expect(stats.loaded_models).toEqual(['bitnet-b1.58']);
            expect(stats.avg_latency_ms).toBeGreaterThanOrEqual(15);
            expect(stats.avg_latency_ms).toBeLessThanOrEqual(55); // max: round(15 + 40) = 55
        }
    });
});

